insert into EMAILFILTERPLACEOFUSE (EMAILFILTERPLACEOFUSEID, EMAIL_FILTER_HANDLING_ID, PLACEOFUSE, DATE_NEW, USER_NEW)
select UUID(), EMAIL_FILTER_HANDLINGID, 'BulkMail', CURRENT_TIMESTAMP, 'migrationUser'
from EMAIL_FILTER_HANDLING;

insert into EMAILFILTERPLACEOFUSE (EMAILFILTERPLACEOFUSEID, EMAIL_FILTER_HANDLING_ID, PLACEOFUSE, DATE_NEW, USER_NEW)
select uuid_in(md5(random()::text || clock_timestamp()::text)::cstring), EMAIL_FILTER_HANDLINGID, 'BulkMail', CURRENT_TIMESTAMP, 'migrationUser'
from EMAIL_FILTER_HANDLING;

insert into EMAILFILTERPLACEOFUSE (EMAILFILTERPLACEOFUSEID, EMAIL_FILTER_HANDLING_ID, PLACEOFUSE, DATE_NEW, USER_NEW)
select SYS_GUID(), EMAIL_FILTER_HANDLINGID, 'BulkMail', CURRENT_TIMESTAMP, 'migrationUser'
from EMAIL_FILTER_HANDLING;

insert into EMAILFILTERPLACEOFUSE (EMAILFILTERPLACEOFUSEID, EMAIL_FILTER_HANDLING_ID, PLACEOFUSE, DATE_NEW, USER_NEW)
select NEWID(), EMAIL_FILTER_HANDLINGID, 'BulkMail', CURRENT_TIMESTAMP, 'migrationUser'
from EMAIL_FILTER_HANDLING;
